    // Map: XOR_Sum -> Min_Count
    // Using mutable map for efficient updates
    val map = mutable.Map[Long, Int]()

    // Iterate through all 2^n subsets using bitmasks
    // Since n <= 20, 2^n fits within standard integer types for iteration limit.
    val numSubsets = 1L << n
    for (i <- 0 until numSubsets.toInt) {
        var currentXorSum: Long = 0
        var currentCount: Int = 0

        for (j <- 0 until n) {
            if ((i >> j) & 1 == 1) {
                currentXorSum = currentXorSum xor arr(j)
                currentCount += 1
            }
        }

        // Update map: store minimum count for this XOR sum
        val existingCount = map.getOrElse(currentXorSum, Int.MaxValue)
        if (currentCount < existingCount) {
            map.update(currentXorSum, currentCount)
        }
    }
    map.toMap // Convert mutable map to immutable for safety during lookup
}

/**
 * Finds the minimum number of elements to remove from nums such that the XOR sum of remaining elements equals target.
 * This is equivalent to finding the minimum size subset D whose XOR sum equals (TotalXorSum XOR target).
 */
